/// <summary>
/// Abhinav - Active method for InventJournalName - to make fields visible
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;
    ret = next active();

    InventJournalName inventJournalName = this.cursor();

    if(ETGCanadaParameters::find().EnableAutoCreateBOM && inventJournalName.JournalType == InventJournalType::BOM)
    {
        this.formRun().design().controlName(FormControlstr(InventJournalName,ETGAutoPostBOMJournal)).visible(true);
    }
    else
    {
        this.formRun().design().controlName(FormControlstr(InventJournalName,ETGAutoPostBOMJournal)).visible(false);
    }

    if(ETGCanadaParameters::find().SelectJournalForAutoCreation && inventJournalName.JournalType == InventJournalType::BOM)
    {
        this.formRun().design().controlName(FormControlstr(InventJournalName,ETGSelectJournalForAutoCreation)).visible(true);
    }
    else
    {
        this.formRun().design().controlName(FormControlstr(InventJournalName,ETGSelectJournalForAutoCreation)).visible(false);
    }

    return ret;
}
